+            .collect::<Vec<f32>>();
+
+        if embedding.len() != self.dims {
+            return Err(format!(
+                "Embedding dimension mismatch: expected {}, got {}",
+                self.dims,
+                embedding.len()
+            ));
+        }
+
+        Ok(embedding)
+    }
